1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const LOYALTY_DISCOUNT_RATE = 0.2;
4	const LOYALTY_THRESHOLD_YEARS = 2;
5	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
6	const COMPONENT_BLOCK_OF_3_PRICE = 60;
7	const COMPONENT_BLOCK_SIZE = 3;
8	const CURSE_SURCHARGE_RATE = 0.5;
9	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
10	const HIGH_ENCHANTMENT_THRESHOLD = 5;
11	const CLAIM_DEDUCTIBLE = 100;
12	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
13	const HIGH_ENCHANTMENT_CLAIM_RATE = 0.5;
14	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	type Item = {
26	  type: string;
27	  cursed?: boolean;
28	  enchantment?: number;
29	  material?: string;
30	};
31	type QuoteStep = { type: "quote"; items: Item[] };
32	type Damage = { itemType: string; amount: number };
33	type Incident = { cause: string; damages: Damage[] };
34	type ClaimStep = { type: "claim"; policy: number; incident: Incident };
35	type Step = QuoteStep | ClaimStep;
36	type Customer = { yearsWithMHPCO: number };
37	type Scenario = { customer?: Customer; steps: Step[] };
38	
39	function groupByType(items: Item[]): Map<string, Item[]> {
40	  const groups = new Map<string, Item[]>();
41	  for (const item of items) {
42	    const group = groups.get(item.type) ?? [];
43	    group.push(item);
44	    groups.set(item.type, group);
45	  }
46	  return groups;
47	}
48	
49	function isHighlyEnchanted(item: Item): boolean {
50	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
51	}
52	
53	function itemBasePrice(item: Item): number {
54	  return BASE_PREMIUMS[item.type];
55	}
56	
57	function itemPriceWithSurcharges(item: Item): number {
58	  const base = itemBasePrice(item);
59	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
60	  const highEnchantmentSurcharge = isHighlyEnchanted(item)
61	    ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
62	    : 0;
63	  return base + curseSurcharge + highEnchantmentSurcharge;
64	}
65	
66	function sumGroup(type: string, group: Item[], itemPrice: (item: Item) => number): number {
67	  if (COMPONENT_TYPES.has(type) && group.length === COMPONENT_BLOCK_SIZE) {
68	    return COMPONENT_BLOCK_OF_3_PRICE;
69	  }
70	  return group.reduce((sum, item) => sum + itemPrice(item), 0);
71	}
72	
73	function sumItems(items: Item[], itemPrice: (item: Item) => number): number {
74	  return Array.from(groupByType(items)).reduce(
75	    (total, [type, group]) => total + sumGroup(type, group, itemPrice),
76	    0,
77	  );
78	}
79	
80	function calculatePremium(items: Item[], isLoyalCustomer: boolean, isFollowUp: boolean): number {
81	  const policyBase = sumItems(items, itemPriceWithSurcharges);
82	  const unmodifiedBase = sumItems(items, itemBasePrice);
83	  const firstInsuranceSurcharge = unmodifiedBase * FIRST_INSURANCE_RATE;
84	  const loyaltyDiscount = isLoyalCustomer ? unmodifiedBase * LOYALTY_DISCOUNT_RATE : 0;
85	  const followUpDiscount = isFollowUp ? unmodifiedBase * FOLLOW_UP_DISCOUNT_RATE : 0;
86	  return policyBase - loyaltyDiscount - followUpDiscount + firstInsuranceSurcharge + PROCESSING_FEE;
87	}
88	
89	function calculatePayout(incident: Incident, policyItems: Item[]): number {
90	  return incident.damages.reduce((sum, damage) => {
91	    const item = policyItems.find((i) => i.type === damage.itemType);
92	    const reimbursable =
93	      item && (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
94	        ? damage.amount * HIGH_ENCHANTMENT_CLAIM_RATE
95	        : damage.amount;
96	    return sum + Math.max(0, reimbursable - CLAIM_DEDUCTIBLE);
97	  }, 0);
98	}
99	
100	export function runScenario(
101	  scenario: unknown,
102	): { results: ({ premium: number } | { payout: number })[] } {
103	  const { customer, steps } = scenario as Scenario;
104	  const isLoyalCustomer = (customer?.yearsWithMHPCO ?? 0) >= LOYALTY_THRESHOLD_YEARS;
105	  let quoteCount = 0;
106	  const results = steps.map((step) => {
107	    if (step.type === "claim") {
108	      const policyStep = steps[step.policy] as QuoteStep;
109	      return { payout: Math.floor(calculatePayout(step.incident, policyStep.items)) };
110	    }
111	    const isFollowUp = quoteCount > 0;
112	    quoteCount++;
113	    return {
114	      premium: Math.ceil(calculatePremium(step.items, isLoyalCustomer, isFollowUp)),
115	    };
116	  });
117	  return { results };
118	}
